    return res.status(400).send({ error: 'Phone number must be in the format XXX-XXX-XXXX' });
  }

  if (age < 18 || age > 100) {
    return res.status(400).send({ error: 'Age must be between 18 and 100' });
  }

  // If all validation passes, save the data to the database
  res.send({ message: 'Data saved successfully' });
});
