const mongoose = require('mongoose');

mongoose.connect('mongodb+srv://username:password@cluster-name.mongodb.net/user-database', { useNewUrlParser: true, useUnifiedTopology: true });

const userSchema = new mongoose.Schema({
  username: String,
  password: String
});

